import { NextRequest, NextResponse } from 'next/server'
import { supabase } from '../../../lib/supabase'

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { prompt, type, settings, userId } = body

    // Validate input
    if (!prompt || !type) {
      return NextResponse.json(
        { error: 'Missing required fields: prompt and type' },
        { status: 400 }
      )
    }

    // Check user credits (if userId provided)
    if (userId) {
      const { data: user, error: userError } = await supabase
        .from('users')
        .select('credits')
        .eq('id', userId)
        .single()

      if (userError || !user) {
        return NextResponse.json(
          { error: 'User not found' },
          { status: 404 }
        )
      }

      if (user.credits <= 0) {
        return NextResponse.json(
          { error: 'Insufficient credits' },
          { status: 402 }
        )
      }
    }

    // Mock generation delay
    await new Promise(resolve => setTimeout(resolve, 1500))

    // Mock response based on content type
    let result = ''
    switch (type) {
      case 'text':
        result = `Generated text content: "${prompt}"\n\nThis is a sample generated text based on your prompt. In a real implementation, this would be generated by an AI model like GPT-4 or similar. The content would be tailored to your specific requirements and the tone/style settings you've selected.`
        break
      case 'image':
        result = 'data:image/svg+xml;base64,'
        break
      case 'audio':
        result = 'data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBSuBzvLZiTYIG2m98OScTgwOUarm7blmGgU7k9n1unEiBC13yO/eizEIHWq+8+OWT'
        break
      case 'video':
        result = 'data:video/mp4;base64,'
        break
      default:
        return NextResponse.json(
          { error: 'Unsupported content type' },
          { status: 400 }
        )
    }

    // Store generation in database
    try {
      const { data: generation, error: insertError } = await supabase
        .from('generations')
        .insert({
          user_id: userId || null,
          type,
          prompt,
          result,
          status: 'completed',
          config: settings || {}
        })
        .select()
        .single()

      if (insertError) {
        console.error('Database insert error:', insertError)
        // If database tables don't exist or connection fails, return a mock response
        if (insertError.code === '42P01' || insertError.message?.includes('fetch failed')) {
          const mockResponse = {
            id: `mock-${Date.now()}`,
            type,
            content: result,
            timestamp: new Date().toISOString(),
            settings: settings || {},
            prompt
          }
          return NextResponse.json(mockResponse)
        }
        return NextResponse.json(
          { error: 'Failed to save generation' },
          { status: 500 }
        )
      }

      const response = {
        id: generation.id,
        type: generation.type,
        content: generation.result,
        timestamp: generation.created_at,
        settings: generation.config,
        prompt: generation.prompt
      }

      return NextResponse.json(response)
    } catch (error) {
      console.error('Database connection error:', error)
      // Return mock response if database is not available
      const mockResponse = {
        id: `mock-${Date.now()}`,
        type,
        content: result,
        timestamp: new Date().toISOString(),
        settings: settings || {},
        prompt
      }
      return NextResponse.json(mockResponse)
    }

    // Deduct credits if user is authenticated
    if (userId) {
      try {
        const { error: creditError } = await supabase
          .from('users')
          .update({ credits: supabase.rpc('decrement_credits', { user_id: userId }) })
          .eq('id', userId)

        if (creditError) {
          console.error('Credit deduction error:', creditError)
        }
      } catch (error) {
        console.error('Credit deduction failed:', error)
      }
    }
  } catch (error) {
    console.error('Generation error:', error)
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    )
  }
} 